<div class="javascript-example">
    <pre><code class="language-javascript">const url = new URL(
    "https://waqty.alemtayaz.shop/public/api/admin/services"
);

const params = {
    "provider_uuid": "66529e01-d113-3473-8d6f-9e11e09332ea",
    "sub_category_uuid": "66529e01-d113-3473-8d6f-9e11e09332ea",
    "active": "0",
    "trashed": "consequatur",
    "search": "consequatur",
    "per_page": "15",
};
Object.keys(params)
    .forEach(key =&gt; url.searchParams.append(key, params[key]));

const headers = {
    "Accept-Language": "ar|en",
    "Authorization": "Bearer {token}",
    "Content-Type": "application/json",
    "Accept": "application/json",
};

let body = {
    "provider_uuid": "123e4567-e89b-12d3-a456-426614174000",
    "sub_category_uuid": "123e4567-e89b-12d3-a456-426614174111",
    "active": true,
    "trashed": "with",
    "search": "cleaning",
    "per_page": 15
};

fetch(url, {
    method: "GET",
    headers,
    body: JSON.stringify(body),
}).then(response =&gt; response.json());</code></pre></div>

